private static class DelegatingMapDeserializer extends StdKeyValueDeserializer implements ResolvableDeserializer {

	protected static final long serialVersionUID = 1L;

	/** Default key deserializer to use when not configured differently */
	private static final KeyDeserializer DEFAULT_KEY_DESERIALIZER;
	static {
	    /* [bug] missing code -- replace below line:
	        DEFAULT_KEY_DESERIALIZER = new StringKeyDeserializer();
	      With these lines: */
	    try {
          DEFAULT_KEY_DESERIALIZER = (KeyDeserializer) Class.forName("com.fasterxml.jackson.databind.deser.std.StringKeyDeserializer").newInstance();
     	 } catch (InstantiationException e) {
             throw new RuntimeException(e);
         } catch (IllegalAccessException e) {
             throw new RuntimeException(e);
         } catch (ClassNotFoundException e) {
             throw new RuntimeException(e);
    		}
	}

	/*
	 * / ***********************************************************************
	 * Base method implementations
	 * ************************************************************************
	 */

	public Map<?, ?> convert(JsonNode rootNode) throws IOException {
			if (rootNode == null || rootNode instanceof NullNode) {
				return _emptyMap;
			}
			// If single valued - wrap into array to process as usual
			if (rootNode instanceof TextNode) {
					return Collections.singletonMap((String)DEFAULT_KEY_DESERIALIZER.deserializeKey(null, ((TextNode) rootNode).textValue()), _emptyArray);
			}
			assert (rootNode instanceof ObjectNode);
			Iterator<? extends JsonNode> elements = rootNode.elements();
			int i = 0;
			int size = rootNode.size();
			Map<Object, Object> result = new HashMap<>(size << 1);
			while (elements.hasNext()) {
				i++;
				final Object v = elements.next();
				String key = (String)_keyDeserializer.deserializeKey(_keyClass, v);
				Object value = _valueDeserializer.deserialize(v);
				if (!result.containsKey(key)) {
					result.put(key, value);
				}
			}
			return result;
		}

		/*
		* / ******************************************************************************
		* Construction
		* ******************************************************************************
		*/

		public DelegatingMapDeserializer(JavaType keyType, JavaType valueType) {
			super(keyType, valueType);
		}

	}

